const targetX = args.x;
const targetZ = args.z;
const radius = args.radius;

const findSword = function () {
  return bot.inventory.items().find(function (item) {
    return item.name.includes('sword') || item.name.includes('axe');
  });
};

startBackgroundSkill(bot, 'kneel_and_defend', async function (token) {
  const canContinue = function () {
    return !token.cancelled && bot.health > 0 && Boolean(bot.entity);
  };

  // Equipment phase
  const sword = findSword();
  if (sword) {
    try {
      await bot.equip(sword, 'hand');
    } catch (err) {}
  }

  // Movement phase
  const movements = new Movements(bot);
  bot.pathfinder.setMovements(movements);
  const goal = new goals.GoalNear(targetX, bot.entity.position.y, targetZ, radius);

  try {
    await bot.pathfinder.goto(goal);
  } catch (err) {
    // Even if pathfinding fails or is interrupted, we continue to the defensive stance if possible
  }

  // Defensive loop
  while (canContinue()) {
    if (bot.physicsEnabled) {
      // Maintain sneak (kneel)
      bot.setControlState('sneak', true);

      // Orient towards nearest potential threat
      const threat = bot.nearestEntity(function (e) {
        return (e.type === 'mob' || e.type === 'player') && e.id !== bot.entity.id && e.position.distanceTo(bot.entity.position) < 15;
      });

      if (threat) {
        bot.lookAt(threat.position.offset(0, threat.height || 1.6, 0));
      }
    }

    await new Promise(function (resolve) { setTimeout(resolve, 200); });

    if (token.cancelled) {
      bot.setControlState('sneak', false);
      break;
    }
  }

  bot.setControlState('sneak', false);
});

return "<DEFENDING>: Moving to safety at (" + targetX + ", " + targetZ + ") and kneeling in a defensive posture.";
